import SwiftUI
import Charts
struct DashboardView:View{@EnvironmentObject var app:AppState;private let columns=[GridItem(.flexible()),GridItem(.flexible())];var body:some View{NavigationStack{ScrollView{VStack(alignment:.leading,spacing:18){header;if let m=app.metric{LazyVGrid(columns:columns,spacing:12){MetricCard(title:"CPU",value:Units.percent(m.cpuPercent),detail:String(format:"Load %.2f",m.load1),icon:"cpu",tint:color(m.cpuPercent));MetricCard(title:"Memory",value:Units.percent(m.ramPercent),detail:"\(Units.bytes(m.ramUsed)) of \(Units.bytes(m.ramTotal))",icon:"memorychip",tint:color(m.ramPercent));MetricCard(title:"Disk",value:Units.percent(m.diskPercent),detail:"\(Units.bytes(m.diskAvailable)) free",icon:"internaldrive",tint:color(m.diskPercent));MetricCard(title:"Network",value:Units.rate(m.networkRxBps),detail:"↑ \(Units.rate(m.networkTxBps))",icon:"arrow.up.arrow.down",tint:.cyan)};chart(m)}else{ContentUnavailableView("Waiting for metrics",systemImage:"waveform.path.ecg",description:Text("Live data will appear after the server responds."))}}.padding()}.refreshable{await app.refresh()}.navigationTitle("Dashboard")}}
 private var header:some View{HStack{VStack(alignment:.leading){Text(app.server?.name ?? "Local server").font(.title2.bold());HStack{Circle().fill(statusColor).frame(width:9,height:9);Text(statusLabel);if let m=app.metric{Text("• Updated \(Date(timeIntervalSince1970:m.timestamp/1000),style:.relative)")}}.font(.caption).foregroundStyle(.secondary)};Spacer();if let m=app.metric{Text(Units.duration(m.uptime)).font(.callout.monospacedDigit())}}}
 private func chart(_ m:Metric)->some View{VStack(alignment:.leading){HStack{Text("CPU — Last hour").font(.headline);Spacer();Text(Units.percent(m.cpuPercent)).monospacedDigit()};Chart(app.history){point in LineMark(x:.value("Time",Date(timeIntervalSince1970:point.timestamp/1000)),y:.value("CPU",point.cpuPercent ?? 0)).foregroundStyle(.cyan).interpolationMethod(.catmullRom);AreaMark(x:.value("Time",Date(timeIntervalSince1970:point.timestamp/1000)),y:.value("CPU",point.cpuPercent ?? 0)).foregroundStyle(.linearGradient(colors:[.cyan.opacity(0.3),.clear],startPoint:.top,endPoint:.bottom))}.chartYScale(domain:0...100).frame(height:210)}.padding().background(.thinMaterial,in:RoundedRectangle(cornerRadius:18))}
 private func color(_ v:Double?)->Color{guard let v else{return.secondary};return v>=90 ? .red:v>=75 ? .orange:.green};private var statusLabel:String{app.healthStatus=="connecting" ? "Connecting…":app.healthStatus.capitalized};private var statusColor:Color{app.healthStatus=="critical" ? .red:app.healthStatus=="warning" ? .orange:app.healthStatus=="healthy" ? .green:.gray}}
